fn gc_control_simple(&mut self, op: i32) -> Result<i32, LuaError> {
    let args = match op {
        0 => lua_vm::api::GcArgs::Stop,
        1 => lua_vm::api::GcArgs::Restart,
        2 => lua_vm::api::GcArgs::Collect,
        _ => return Err(LuaError::runtime(format_args!(
            "invalid GC option {}", op
